#include <stdio.h>
#include <stdlib.h>

// Function to swap two elements
void swap(int *a, int *b) {
    int temp = *a;
    *a = *b;
    *b = temp;
}

// Function to check if a person is better than another
int isBetter(int person1[3], int person2[3]) {
    int i;
    for (i = 0; i < 3; i++) {
        if (person1[i] < person2[i]) {
            return 0;
        }
    }
    for (i = 0; i < 3; i++) {
        if (person1[i] > person2[i]) {
            return 1;
        }
    }
    return 0;
}

// Function to generate all permutations of the team members
void generatePermutations(int team[3][3], int index, int size) {
    if (index == size) {
        // Check if the current permutation satisfies the condition
        if (isBetter(team[1], team[0]) && isBetter(team[2], team[1])) {
            printf("yes\n");
            return;
        }
    } else {
        int i;
        for (i = index; i < size; i++) {
            swap(team[index], team[i]);
            generatePermutations(team, index + 1, size);
            swap(team[index], team[i]);
        }
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int team[3][3];
        int i;
        for (i = 0; i < 3; i++) {
            scanf("%d %d %d", &team[i][0], &team[i][1], &team[i][2]);
        }
        generatePermutations(team, 0, 3);
        printf("no\n");
    }
    return 0;
}

