import java.util.Scanner;
public class Main {
    // Function to check if a person is better than another
    public static boolean isBetter(int[] person1, int[] person2) {
        boolean better = false;
        for (int i = 0; i < 3; i++) {
            if (person1[i] < person2[i]) {
                return false;
            }
            if (person1[i] > person2[i]) {
                better = true;
            }
        }
        return better;
    }

    // Function to generate all permutations of the team members
    public static void generatePermutations(int[][] team, int index, int size) {
        if (index == size) {
            // Check if the current permutation satisfies the condition
            if (isBetter(team[1], team[0]) && isBetter(team[2], team[1])) {
                System.out.println("yes");
                System.exit(0);
            }
        } else {
            for (int i = index; i < size; i++) {
                int[] temp = team[index];
                team[index] = team[i];
                team[i] = temp;
                generatePermutations(team, index + 1, size);
                temp = team[index];
                team[index] = team[i];
                team[i] = temp;
            }
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int[][] team = new int[3][3];
            for (int i = 0; i < 3; i++) {
                team[i][0] = scanner.nextInt();
                team[i][1] = scanner.nextInt();
                team[i][2] = scanner.nextInt();
            }
            generatePermutations(team, 0, 3);
            System.out.println("no");
        }
    }
}

