// Function to get all permutations of an array
function getPermutations(array) {
    if (array.length === 1) {
        return [array];
    }
    const permutations = [];
    for (let i = 0; i < array.length; i++) {
        const rest = array.slice(0, i).concat(array.slice(i + 1));
        for (let permutation of getPermutations(rest)) {
            permutations.push([array[i]].concat(permutation));
        }
    }
    return permutations;
}

